  ('social-worker-moex-02142', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '一位媳婦辭去工作長年在家中照顧公婆，過程中沒有得到妯娌的協助與支持，反而常常被責怪照顧不周， 照顧者因而求助社會工作者。試問若你（妳）是這位社會工作者，你（妳）覺得以下那個情況不是這位 求助者所面臨的議題？', '["性別不平等的議題", "有足夠的家庭及社會支持", "照顧者被視為愛的勞務沒受到關注", "需要相關的照顧服務介入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02143', 'social-worker', 'social-worker-moex-106-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '以下的描述不是社會工作者投入食物銀行的服務目的？', '["社會工作者透過食物銀行的服務可協助弱勢者物資的需求", "社會工作者可以透過食物銀行的服務深入家庭提供專業的服務", "社會工作者可以透過食物銀行的服務，評估服務對象的其他服務需求", "社會工作者可以透過食物銀行的服務增加服務亮點"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "08042f9fdcbd", "answer_pdf_sha1": "46e9970ef553", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
